import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting premiums", () => {
    it("should compute premium for a single sword for a new customer", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it.todo("should compute premium for other item types (amulet, staff, potion)");
    it.todo("should sum premiums for multiple items");
    it.todo("should compute premium for a single component");
    it.todo("should apply bundle pricing for 3 alike components");
    it.todo("should add 50% surcharge for cursed items");
    it.todo("should add 30% surcharge for highly enchanted items (enchantment >= 5)");
    it.todo("should apply 20% loyalty discount for long-standing customers (>= 2 years)");
    it.todo("should apply 15% discount on second contract and no first-insurance surcharge");
    it.todo("should round amounts up in MHPCO's favor");
  });

  describe("Processing claims", () => {
    it.todo("should apply 100G deductible to a basic claim");
    it.todo("should reimburse high-enchantment items (>= 8) at 50%");
    it.todo("should fully reimburse dragon material items");
    it.todo("should cap total payout at twice the insurance sum");
  });
});

