const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const INSURANCE_VALUES: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
};

const COMPONENT_INSURANCE_VALUE = 250;
const DEDUCTIBLE = 100;
const CAP_MULTIPLIER = 2;

const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BUNDLE_SIZE = 3;
const COMPONENT_BUNDLE_PREMIUM = 60;
const CURSED_SURCHARGE = 1.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE = 1.3;
const LOYALTY_THRESHOLD_YEARS = 2;
const LOYALTY_DISCOUNT = 0.8;
const MULTI_CONTRACT_DISCOUNT = 0.85;
const FIRST_INSURANCE_SURCHARGE = 1.1;
const PROCESSING_FEE = 5;

function ceilWithPrecision(value: number): number {
  return Math.ceil(parseFloat(value.toFixed(2)));
}

function isComponent(item: any): boolean {
  return !(item.type in BASE_PREMIUMS);
}

function computeComponentPremium(components: any[]): number {
  const groups: Record<string, number> = {};
  for (const item of components) {
    groups[item.type] = (groups[item.type] ?? 0) + 1;
  }
  let total = 0;
  for (const count of Object.values(groups)) {
    const bundles = Math.floor(count / COMPONENT_BUNDLE_SIZE);
    const remainder = count % COMPONENT_BUNDLE_SIZE;
    total += bundles * COMPONENT_BUNDLE_PREMIUM + remainder * COMPONENT_BASE_PREMIUM;
  }
  return total;
}

function computeBasePremium(items: any[]): number {
  const mainItems = items.filter((item: any) => !isComponent(item));
  const components = items.filter((item: any) => isComponent(item));
  const mainPremium = mainItems.reduce(
    (sum: number, item: any) => {
      let itemPremium = BASE_PREMIUMS[item.type];
      if (item.cursed) itemPremium *= CURSED_SURCHARGE;
      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) itemPremium *= HIGH_ENCHANTMENT_SURCHARGE;
      return sum + itemPremium;
    },
    0
  );
  return mainPremium + computeComponentPremium(components);
}

export function processScenario(scenario: any): any {
  const customer = scenario.customer;
  let quoteCount = 0;
  const policies: Record<number, { insuranceSum: number; remainingCap: number }> = {};
  const results = scenario.steps.map((step: any, index: number) => {
    if (step.op === "quote") {
      quoteCount++;
      const basePremium = computeBasePremium(step.items);
      let adjusted: number;
      if (quoteCount === 1) {
        adjusted = basePremium * FIRST_INSURANCE_SURCHARGE;
      } else {
        adjusted = basePremium * MULTI_CONTRACT_DISCOUNT;
      }
      if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) adjusted *= LOYALTY_DISCOUNT;
      const premium = ceilWithPrecision(adjusted) + PROCESSING_FEE;
      const insuranceSum = step.items.reduce(
        (sum: number, item: any) => sum + (INSURANCE_VALUES[item.type] ?? COMPONENT_INSURANCE_VALUE),
        0
      );
      policies[index] = { insuranceSum, remainingCap: insuranceSum * CAP_MULTIPLIER };
      return { premium };
    }
    if (step.op === "claim") {
      const policy = policies[step.policy];
      const totalDamage = step.incident.damages.reduce(
        (sum: number, d: any) => sum + d.amount,
        0
      );
      const payout = Math.max(0, totalDamage - DEDUCTIBLE);
      const actualPayout = Math.min(payout, policy.remainingCap);
      policy.remainingCap -= actualPayout;
      return { payout: actualPayout, remainingCap: policy.remainingCap };
    }
    return {};
  });
  return { results };
}

import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting premiums", () => {
    it("should compute premium for a single sword for a new customer", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("should compute premium for other item types (amulet, staff, potion)", () => {
      const amuletResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 2, cursed: false },
            ],
          },
        ],
      });
      expect(amuletResult.results[0]).toEqual({ premium: 71 });

      const staffResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff", material: "oak", enchantment: 1, cursed: false },
            ],
          },
        ],
      });
      expect(staffResult.results[0]).toEqual({ premium: 93 });

      const potionResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(potionResult.results[0]).toEqual({ premium: 49 });
    });
    it("should sum premiums for multiple items", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
              { type: "amulet", material: "silver", enchantment: 2, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 181 });
    });
    it("should compute premium for a single component", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 33 });
    });
    it("should apply bundle pricing for 3 alike components", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it("should add 50% surcharge for cursed items", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: true },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 170 });
    });
    it("should add 30% surcharge for highly enchanted items (enchantment >= 5)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff", material: "oak", enchantment: 6, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 120 });
    });
    it("should apply 20% loyalty discount for long-standing customers (>= 2 years)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 3 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 93 });
    });
    it("should apply 15% discount on second contract and no first-insurance surcharge", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 115 });
      expect(result.results[1]).toEqual({ premium: 90 });
    });
    it("should round amounts up in MHPCO's favor", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 3 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 2, cursed: true },
            ],
          },
        ],
      });
      // amulet base 60, cursed *1.5=90, first insurance *1.1=99, loyalty *0.8=79.2
      // ceil(79.2)=80, +5 processing = 85
      expect(result.results[0]).toEqual({ premium: 85 });
    });
  });

  describe("Processing claims", () => {
    it("should apply 100G deductible to a basic claim", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 2, cursed: false },
            ],
          },
          {
            op: "claim" as const,
            policy: 0,
            incident: {
              cause: "fire",
              damages: [
                { itemType: "amulet", amount: 300 },
              ],
            },
          },
        ],
      });
      expect(result.results[1]).toEqual({ payout: 200, remainingCap: 1000 });
    });
    it.todo("should reimburse high-enchantment items (>= 8) at 50%");
    it.todo("should fully reimburse dragon material items");
    it.todo("should cap total payout at twice the insurance sum");
  });
});

